// ============================================================
// Lorevnter - 运行时状态 (Pinia)
// ============================================================
import { getLogBuffer } from './logger';
export const useRuntimeStore = defineStore('lorevnter_runtime', () => {
    // ── 窗口状态 ──
    const windowVisible = ref(false);
    const currentTab = ref('worldbooks');
    // ── 世界书浏览状态 ──
    /** 当前选中的世界书名（Tab 切换不丢失） */
    const worldbookSelectedName = ref(null);
    // ── 日志（引用 logger 模块的缓冲区） ──
    /** 响应式日志快照，通过 refreshLogs() 手动刷新 */
    const logEntries = ref([]);
    // ── AI 调用历史 ──
    const aiCallHistory = ref([]);
    // ── 管线状态 ──
    const pipelineStatus = ref('idle');
    /** 最近一次管线结果摘要 */
    const pipelineLastMessage = ref('');
    /** AI 流式返回实时文本 */
    const streamingText = ref('');
    /** 管线开始时间戳 */
    const pipelineStartTime = ref(0);
    /** 从 logger 缓冲区刷新日志到响应式状态 */
    function refreshLogs() {
        logEntries.value = [...getLogBuffer()];
    }
    /** 清空 AI 调用历史 */
    function clearAiHistory() {
        aiCallHistory.value = [];
    }
    return {
        windowVisible,
        currentTab,
        worldbookSelectedName,
        logEntries,
        aiCallHistory,
        pipelineStatus,
        pipelineLastMessage,
        streamingText,
        pipelineStartTime,
        refreshLogs,
        clearAiHistory,
    };
});
